  ('promotion-c5fb3965-moex-00074', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '甲為某機關公務人員因辦理業務有重大疏失且不服長官命令，態度惡劣，經該機關公務人員考績 暨甄選委員會審議後，依據公務人員考績法作成記一大過之決議。甲於收受機關公文書通知其考 績會決議核予記一大過之結果後不服，依法應如何救濟？', '["向服務機關的上級機關提起訴願", "逕行向行政法院提起撤銷之訴", "向公務人員保障暨培訓委員會提起復審", "向服務機關提起申訴 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、40130 41130、70130 71130"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00075', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '有關訴願法的「不利益變更禁止原則」，下列敘述何者錯誤？', '["以訴願管轄機關為規範對象，不及於原處分機關", "原處分裁量濫用或逾越裁量權限經撤銷後，原處分機關重為處分得較原行政處分不利，不受不 利益變更禁止原則之拘束", "除非原行政處分因裁量濫用或逾越裁量權限經撤銷後，否則原處分機關重為處分較原行政處分 不利，違反禁止恣意原則", "訴願管轄機關及原處分機關皆為規範對象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
