  ('promotion-c5fb3965-moex-00078', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '下列有關行政契約的敘述，依據行政程序法相關規定，何者正確？', '["行政機關得與人民締結行政契約，創設私法性質的法律關係", "行政機關為能有效達成行政目的解決爭執，得與人民締結行政契約方式代替行政處分", "行政契約內容有關對待給付義務，行政機關與人民給付不須相當", "行政契約之締結除法規另有規定外，得以口頭或書面方式為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
